import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"Regex Engine Internals","description":"","frontmatter":{},"headers":[],"relativePath":"std/regex/internals.md","filePath":"std/regex/internals.md"}'),i={name:"std/regex/internals.md"};function s(r,e,l,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="regex-engine-internals" tabindex="-1">Regex Engine Internals <a class="header-anchor" href="#regex-engine-internals" aria-label="Permalink to &quot;Regex Engine Internals&quot;">​</a></h1><h2 id="compilation-pipeline" tabindex="-1">Compilation Pipeline <a class="header-anchor" href="#compilation-pipeline" aria-label="Permalink to &quot;Compilation Pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Source Pattern → Parser → AST (Pattern/Sequence) → Thompson NFA → Bytecode (Prog)</span></span>\n<span class="line"><span>                                                                         ↓</span></span>\n<span class="line"><span>                                                                 One-Pass DFA (if eligible)</span></span></code></pre></div><ol><li><strong>Parser</strong> (<code>parser.vx</code>): Handles full regex syntax including character classes, quantifiers, alternation, groups, lookahead, backreferences, and inline flags like <code>(?i)</code>.</li><li><strong>AST</strong> (<code>ast.vx</code>): Produces <code>Pattern</code> → <code>Sequence</code> tree with <code>Span</code> position tracking.</li><li><strong>Thompson Compiler</strong> (<code>thompson.vx</code>): Converts AST into NFA bytecode with epsilon-free transitions.</li><li><strong>One-Pass DFA</strong> (<code>onepass.vx</code>): When the NFA is unambiguous, builds a direct DFA for O(n) matching.</li></ol><h2 id="execution-engines" tabindex="-1">Execution Engines <a class="header-anchor" href="#execution-engines" aria-label="Permalink to &quot;Execution Engines&quot;">​</a></h2><h3 id="one-pass-dfa-onepass-vx" tabindex="-1">One-Pass DFA (<code>onepass.vx</code>) <a class="header-anchor" href="#one-pass-dfa-onepass-vx" aria-label="Permalink to &quot;One-Pass DFA (`onepass.vx`)&quot;">​</a></h3><p>For simple patterns without ambiguity. O(n) time, no backtracking. Used for patterns like literal strings, simple alternations, and non-overlapping quantifiers.</p><h3 id="simd-prefix-search-thompson-fast-vx" tabindex="-1">SIMD Prefix Search (<code>thompson_fast.vx</code>) <a class="header-anchor" href="#simd-prefix-search-thompson-fast-vx" aria-label="Permalink to &quot;SIMD Prefix Search (`thompson_fast.vx`)&quot;">​</a></h3><p>When the pattern starts with a multi-byte literal (e.g., <code>&quot;HTTP/&quot;</code>, <code>&quot;error:&quot;</code>), the engine extracts this prefix and uses V9 SIMD <code>indexOf</code> to jump directly to candidate positions, skipping large portions of the input.</p><h3 id="lazy-dfa-lazy-dfa-vx" tabindex="-1">Lazy DFA (<code>lazy_dfa.vx</code>) <a class="header-anchor" href="#lazy-dfa-lazy-dfa-vx" aria-label="Permalink to &quot;Lazy DFA (`lazy_dfa.vx`)&quot;">​</a></h3><p>For complex patterns, builds DFA states on-demand with a bounded cache. Avoids the exponential state explosion of full DFA construction while still achieving near-DFA speeds on practical inputs.</p><h3 id="thompson-nfa-thompson-exec-vx" tabindex="-1">Thompson NFA (<code>thompson_exec.vx</code>) <a class="header-anchor" href="#thompson-nfa-thompson-exec-vx" aria-label="Permalink to &quot;Thompson NFA (`thompson_exec.vx`)&quot;">​</a></h3><p>The fallback executor. Simulates all active NFA states simultaneously (parallel matching). Guarantees linear-time matching regardless of pattern complexity — no catastrophic backtracking.</p><h2 id="metadata-optimization" tabindex="-1">Metadata &amp; Optimization <a class="header-anchor" href="#metadata-optimization" aria-label="Permalink to &quot;Metadata &amp; Optimization&quot;">​</a></h2><p>The compiled <code>Prog</code> includes metadata for routing decisions:</p><ul><li><code>prefixLen</code> / <code>prefixBytes</code>: Extracted literal prefix for SIMD acceleration</li><li><code>innerLen</code> / <code>innerBytes</code>: Inner literal for mid-pattern SIMD filtering</li><li>Pattern complexity flags for engine selection</li></ul>',16)])])}const u=a(i,[["render",s]]);export{m as __pageData,u as default};
